-- Table: admin_credentials
DROP TABLE IF EXISTS `admin_credentials`;
CREATE TABLE `admin_credentials` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `admin_id` int(11) NOT NULL,
  `title` varchar(255) NOT NULL,
  `category` enum('Software','Device','Account','Server','Database','API','Other') DEFAULT 'Other',
  `username` varchar(255) DEFAULT NULL,
  `password_encrypted` text DEFAULT NULL,
  `url` varchar(500) DEFAULT NULL,
  `notes` text DEFAULT NULL,
  `tags` varchar(500) DEFAULT NULL,
  `last_used` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_admin_category` (`admin_id`,`category`),
  KEY `idx_tags` (`tags`),
  FULLTEXT KEY `idx_search` (`title`,`notes`,`tags`),
  CONSTRAINT `admin_credentials_ibfk_1` FOREIGN KEY (`admin_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- Table: admin_meetings
DROP TABLE IF EXISTS `admin_meetings`;
CREATE TABLE `admin_meetings` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `admin_id` int(11) NOT NULL,
  `title` varchar(255) NOT NULL,
  `description` text DEFAULT NULL,
  `meeting_with` varchar(255) DEFAULT NULL,
  `meeting_date` date NOT NULL,
  `meeting_time` time NOT NULL,
  `duration_minutes` int(11) DEFAULT 30,
  `location` varchar(255) DEFAULT NULL,
  `meeting_link` varchar(500) DEFAULT NULL,
  `reminder_minutes` int(11) DEFAULT 15,
  `reminder_sent` tinyint(1) DEFAULT 0,
  `status` enum('Scheduled','Completed','Cancelled','Rescheduled') DEFAULT 'Scheduled',
  `notes` text DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_admin_date` (`admin_id`,`meeting_date`),
  KEY `idx_admin_status` (`admin_id`,`status`),
  KEY `idx_reminder` (`meeting_date`,`meeting_time`,`reminder_sent`),
  FULLTEXT KEY `idx_search` (`title`,`description`,`meeting_with`),
  CONSTRAINT `admin_meetings_ibfk_1` FOREIGN KEY (`admin_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- Table: admin_notes
DROP TABLE IF EXISTS `admin_notes`;
CREATE TABLE `admin_notes` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `admin_id` int(11) NOT NULL,
  `title` varchar(255) NOT NULL,
  `content` text DEFAULT NULL,
  `category` enum('General','Project','Meeting','Technical','Personal','Important') DEFAULT 'General',
  `color` varchar(20) DEFAULT '#ffffff',
  `is_pinned` tinyint(1) DEFAULT 0,
  `tags` varchar(500) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_admin_pinned` (`admin_id`,`is_pinned`),
  KEY `idx_admin_category` (`admin_id`,`category`),
  FULLTEXT KEY `idx_search` (`title`,`content`,`tags`),
  CONSTRAINT `admin_notes_ibfk_1` FOREIGN KEY (`admin_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- Table: admin_todos
DROP TABLE IF EXISTS `admin_todos`;
CREATE TABLE `admin_todos` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `admin_id` int(11) NOT NULL,
  `title` varchar(255) NOT NULL,
  `description` text DEFAULT NULL,
  `priority` enum('Low','Medium','High','Urgent') DEFAULT 'Medium',
  `status` enum('Pending','In Progress','Completed','Cancelled') DEFAULT 'Pending',
  `due_date` date DEFAULT NULL,
  `completed_at` timestamp NULL DEFAULT NULL,
  `tags` varchar(500) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_admin_status` (`admin_id`,`status`),
  KEY `idx_admin_priority` (`admin_id`,`priority`),
  KEY `idx_due_date` (`due_date`),
  FULLTEXT KEY `idx_search` (`title`,`description`,`tags`),
  CONSTRAINT `admin_todos_ibfk_1` FOREIGN KEY (`admin_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- Table: assignments
DROP TABLE IF EXISTS `assignments`;
CREATE TABLE `assignments` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `project_id` int(11) NOT NULL,
  `page_id` int(11) DEFAULT NULL,
  `environment_id` int(11) DEFAULT NULL,
  `task_type` enum('page_assignment','env_assignment','testing_task','other','regression') NOT NULL DEFAULT 'other',
  `assigned_user_id` int(11) NOT NULL,
  `assigned_role` varchar(50) DEFAULT NULL,
  `meta` longtext DEFAULT NULL COMMENT 'JSON metadata (json_valid expected)',
  `created_by` int(11) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_assignments_project` (`project_id`),
  KEY `idx_assignments_page` (`page_id`),
  KEY `idx_assignments_env` (`environment_id`),
  KEY `idx_assignments_user` (`assigned_user_id`),
  CONSTRAINT `assignments_fk_env` FOREIGN KEY (`environment_id`) REFERENCES `testing_environments` (`id`) ON DELETE CASCADE,
  CONSTRAINT `assignments_fk_project` FOREIGN KEY (`project_id`) REFERENCES `projects` (`id`) ON DELETE CASCADE,
  CONSTRAINT `assignments_fk_user` FOREIGN KEY (`assigned_user_id`) REFERENCES `users` (`id`),
  CONSTRAINT `fk_assignments_page_id_project` FOREIGN KEY (`page_id`) REFERENCES `project_pages` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=11 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- Table: automated_a11y_findings
DROP TABLE IF EXISTS `automated_a11y_findings`;
CREATE TABLE `automated_a11y_findings` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `project_id` int(11) NOT NULL,
  `page_id` int(11) NOT NULL,
  `rule_id` varchar(120) NOT NULL,
  `title` varchar(255) NOT NULL,
  `severity` varchar(20) NOT NULL DEFAULT 'moderate',
  `description` text NOT NULL,
  `occurrence_count` int(11) NOT NULL DEFAULT 1,
  `examples_json` longtext DEFAULT NULL,
  `scan_url` varchar(1000) DEFAULT NULL,
  `status` varchar(30) NOT NULL DEFAULT 'needs_review',
  `moved_issue_id` int(11) DEFAULT NULL,
  `created_by` int(11) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `actual_results` longtext DEFAULT NULL,
  `incorrect_code` longtext DEFAULT NULL,
  `screenshots_json` longtext DEFAULT NULL,
  `recommendation` longtext DEFAULT NULL,
  `correct_code` longtext DEFAULT NULL,
  `help_url` varchar(1000) DEFAULT NULL,
  `raw_payload` longtext DEFAULT NULL,
  `wcag_sc` varchar(100) DEFAULT NULL,
  `wcag_name` varchar(255) DEFAULT NULL,
  `wcag_level` varchar(20) DEFAULT NULL,
  `scan_urls_json` longtext DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_a11y_project_page_status` (`project_id`,`page_id`,`status`),
  KEY `idx_a11y_created_at` (`created_at`),
  KEY `idx_a11y_moved_issue` (`moved_issue_id`)
) ENGINE=InnoDB AUTO_INCREMENT=584 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

INSERT INTO `automated_a11y_findings` VALUES
('1', '6', '620', 'duplicate-id', 'Duplicate element IDs found', 'medium', 'IDs must be unique to avoid assistive tech conflicts.', '27', '[\"#Capa_1\",\"#SVGRepo_bgCarrier\",\"#SVGRepo_tracerCarrier\",\"#SVGRepo_iconCarrier\",\"#svg8\"]', 'https://sisenable.com/', 'moved_to_final', '281', '6', '2026-02-22 21:59:57', '2026-02-22 22:07:21', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('2', '6', '620', 'link-name', 'Links without accessible name', 'medium', 'Links should have visible text or `aria-label`.', '4', '[\"https://sisenable.com/\",\"#facts1\",\"#facts2\",\"#facts6\"]', 'https://sisenable.com/', 'moved_to_final', '280', '6', '2026-02-22 21:59:57', '2026-02-22 22:07:20', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('4', '6', '636', 'link-name', 'Links must have discernible text', 'high', '', '2', NULL, 'https://www.samcomf.com/knowledge-center/food-for-thought-may-2022-9-lessons-from-nifty50-journey/', 'moved_to_final', '282', '6', '2026-02-22 22:10:33', '2026-02-22 22:14:55', 'Rule: link-name\nImpact: serious\nOccurrences: 2\nEnsure links have discernible text', '<a href=\"/knowledge-center/author/paras/\" class=\"static-avatar author-profile-image\">\n\n<a href=\"/knowledge-center/author/anushree/\" class=\"static-avatar author-profile-image\">', '[\"/uploads/automated_findings/project_6/page_636/20260222_220942_32d957/1771778423249_link-name_6.png\",\"/uploads/automated_findings/project_6/page_636/20260222_220942_32d957/1771778428376_link-name_7.png\"]', 'Links must have discernible text | https://dequeuniversity.com/rules/axe/4.11/link-name?application=axeAPI', '', 'https://dequeuniversity.com/rules/axe/4.11/link-name?application=axeAPI', '{\"rule_id\":\"link-name\",\"title\":\"Links must have discernible text\",\"severity\":\"serious\",\"actual_results\":\"Rule: link-name\\nImpact: serious\\nOccurrences: 2\\nEnsure links have discernible text\",\"incorrect_code\":\"<a href=\\\"/knowledge-center/author/paras/\\\" class=\\\"static-avatar author-profile-image\\\">\\n\\n<a href=\\\"/knowledge-center/author/anushree/\\\" class=\\\"static-avatar author-profile-image\\\">\",\"screenshots\":[\"1771778423249_link-name_6.png\",\"1771778428376_link-name_7.png\"],\"recommendation\":\"Links must have discernible text | https://dequeuniversity.com/rules/axe/4.11/link-name?application=axeAPI\",\"correct_code\":\"\",\"help_url\":\"https://dequeuniversity.com/rules/axe/4.11/link-name?application=axeAPI\",\"occurrence_count\":2,\"raw_nodes\":[{\"any\":[{\"id\":\"has-visible-text\",\"data\":null,\"relatedNodes\":[],\"impact\":\"serious\",\"message\":\"Element does not have text that is visible to screen readers\"},{\"id\":\"aria-label\",\"data\":null,\"relatedNodes\":[],\"impact\":\"serious\",\"message\":\"aria-label attribute does not exist or is empty\"},{\"id\":\"aria-labelledby\",\"data\":null,\"relatedNodes\":[],\"impact\":\"serious\",\"message\":\"aria-labelledby attribute does not exist, references elements that do not exist or references elements that are empty\"},{\"id\":\"non-empty-title\",\"data\":{\"messageKey\":\"noAttr\"},\"relatedNodes\":[],\"impact\":\"serious\",\"message\":\"Element has no title attribute\"}],\"all\":[],\"none\":[{\"id\":\"focusable-no-name\",\"data\":null,\"relatedNodes\":[],\"impact\":\"serious\",\"message\":\"Element is in tab order and does not have accessible text\"}],\"impact\":\"serious\",\"html\":\"<a href=\\\"/knowledge-center/author/paras/\\\" class=\\\"static-avatar author-profile-image\\\">\",\"target\":[\".featured > .post-card-content > .post-card-meta > .author-list > .author-list-item > .static-avatar.author-profile-image\"],\"failureSummary\":\"Fix all of the following:\\n  Element is in tab order and does not have accessible text\\n\\nFix any of the following:\\n  Element does not have text that is visible to screen readers\\n  aria-label attribute does not exist or is empty\\n  aria-labelledby attribute does not exist, references elements that do not exist or references elements that are empty\\n  Element has no title attribute\"},{\"any\":[{\"id\":\"has-visible-text\",\"data\":null,\"relatedNodes\":[],\"impact\":\"serious\",\"message\":\"Element does not have text that is visible to screen readers\"},{\"id\":\"aria-label\",\"data\":null,\"relatedNodes\":[],\"impact\":\"serious\",\"message\":\"aria-label attribute does not exist or is empty\"},{\"id\":\"aria-labelledby\",\"data\":null,\"relatedNodes\":[],\"impact\":\"serious\",\"message\":\"aria-labelledby attribute does not exist, references elements that do not exist or references elements that are empty\"},{\"id\":\"non-empty-title\",\"data\":{\"messageKey\":\"noAttr\"},\"relatedNodes\":[],\"impact\":\"serious\",\"message\":\"Element has no titl