('580', '6', '621', 'image-redundant-alt', 'Alternative text of images should not be repeated as text', 'Minor', '', '2', NULL, 'https://www.samcomf.com/career-open-positions', 'needs_review', NULL, '6', '2026-02-26 17:23:58', '2026-02-26 17:23:58', 'Ensure image alternative is not repeated as text\n\nURL: https://www.samcomf.com/career-open-positions\n\nElement contains <img> element with alt text that duplicates existing text\n- \"Easy & quick\" in \"Filing Complaints on SCORES\"\n\nURL: https://www.samcomf.com/disclaimer\n\nElement contains <img> element with alt text that duplicates existing text\n- \"Easy & quick\" in \"Filing Complaints on SCORES\"', '<img src=\"https://www.samcomf.com/images/quick-response.png\" alt=\"Easy &amp; quick\" width=\"32\" height=\"32\">', '[\"/PMS/uploads/automated_findings/project_6/page_621/20260226_172341_45d308/1772106828820_image-redundant-alt_5.png\",\"/PMS/uploads/automated_findings/project_6/page_621/20260226_172341_45d308/1772106837249_image-redundant-alt_3.png\"]', 'Avoid repeating surrounding visible text in image alternative text.\n- If adjacent text already conveys the same meaning, set image alt to empty (alt=\"\").\n- Keep one clear text label instead of duplicated text + identical alt.', '<img src=\"https://www.samcomf.com/images/quick-response.png\" alt=\"\" width=\"32\" height=\"32\">', '', '{\"rule_id\":\"image-redundant-alt\",\"title\":\"Alternative text of images should not be repeated as text\",\"severity\":\"minor\",\"needs_review_severity\":\"Minor\",\"wcag_sc\":[],\"wcag_name\":\"Alternative text of images should not be repeated as text\",\"wcag_level\":\"\",\"actual_results\":\"Ensure image alternative is not repeated as text\\n\\nURL: https://www.samcomf.com/career-open-positions\\n\\nElement contains <img> element with alt text that duplicates existing text\\n- \\\"Easy & quick\\\" in \\\"Filing Complaints on SCORES\\\"\\n\\nURL: https://www.samcomf.com/disclaimer\\n\\nElement contains <img> element with alt text that duplicates existing text\\n- \\\"Easy & quick\\\" in \\\"Filing Complaints on SCORES\\\"\",\"incorrect_code\":\"<img src=\\\"https://www.samcomf.com/images/quick-response.png\\\" alt=\\\"Easy &amp; quick\\\" width=\\\"32\\\" height=\\\"32\\\">\",\"screenshots\":[\"1772106828820_image-redundant-alt_5.png\",\"1772106837249_image-redundant-alt_3.png\"],\"recommendation\":\"Avoid repeating surrounding visible text in image alternative text.\\n- If adjacent text already conveys the same meaning, set image alt to empty (alt=\\\"\\\").\\n- Keep one clear text label instead of duplicated text + identical alt.\",\"correct_code\":\"<img src=\\\"https://www.samcomf.com/images/quick-response.png\\\" alt=\\\"\\\" width=\\\"32\\\" height=\\\"32\\\">\",\"help_url\":\"\",\"occurrence_count\":2,\"scan_url\":\"https://www.samcomf.com/career-open-positions\",\"scan_urls\":[\"https://www.samcomf.com/career-open-positions\"],\"raw_nodes\":[{\"any\":[],\"all\":[],\"none\":[{\"id\":\"duplicate-img-label\",\"data\":null,\"relatedNodes\":[],\"impact\":\"minor\",\"message\":\"Element contains <img> element with alt text that duplicates existing text\"}],\"impact\":\"minor\",\"html\":\"<img src=\\\"https://www.samcomf.com/images/quick-response.png\\\" alt=\\\"Easy &amp; quick\\\" width=\\\"32\\\" height=\\\"32\\\">\",\"target\":[\"img[alt=\\\"Easy & quick\\\"]\"],\"failureSummary\":\"Fix all of the following:\\n  Element contains <img> element with alt text that duplicates existing text\"},{\"any\":[],\"all\":[],\"none\":[{\"id\":\"duplicate-img-label\",\"data\":null,\"relatedNodes\":[],\"impact\":\"minor\",\"message\":\"Element contains <img> element with alt text that duplicates existing text\"}],\"impact\":\"minor\",\"html\":\"<img src=\\\"https://www.samcomf.com/images/quick-response.png\\\" alt=\\\"Easy &amp; quick\\\" width=\\\"32\\\" height=\\\"32\\\">\",\"target\":[\"img[alt=\\\"Easy & quick\\\"]\"],\"failureSummary\":\"Fix all of the following:\\n  Element contains <im