-- Table: issue_presence_sessions
DROP TABLE IF EXISTS `issue_presence_sessions`;
CREATE TABLE `issue_presence_sessions` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `project_id` int(11) NOT NULL,
  `issue_id` int(11) NOT NULL,
  `user_id` int(11) NOT NULL,
  `session_token` varchar(64) NOT NULL,
  `opened_at` datetime NOT NULL DEFAULT current_timestamp(),
  `last_seen` datetime NOT NULL DEFAULT current_timestamp(),
  `closed_at` datetime DEFAULT NULL,
  `duration_seconds` int(11) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uniq_session_token` (`session_token`),
  UNIQUE KEY `ux_issue_presence_session_token` (`session_token`),
  KEY `idx_session_issue` (`project_id`,`issue_id`),
  KEY `idx_session_user` (`user_id`),
  KEY `idx_session_opened` (`opened_at`),
  KEY `idx_session_closed` (`closed_at`),
  KEY `idx_issue_presence_issue` (`project_id`,`issue_id`,`opened_at`),
  KEY `idx_issue_presence_user` (`user_id`,`opened_at`),
  KEY `idx_issue_presence_open` (`closed_at`,`last_seen`)
) ENGINE=InnoDB AUTO_INCREMENT=170 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

