-- Table: issues
DROP TABLE IF EXISTS `issues`;
CREATE TABLE `issues` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `project_id` int(11) NOT NULL,
  `issue_key` varchar(50) NOT NULL,
  `title` varchar(500) NOT NULL,
  `description` text DEFAULT NULL,
  `type_id` int(11) NOT NULL,
  `priority_id` int(11) NOT NULL,
  `status_id` int(11) NOT NULL,
  `qa_status_id` int(11) DEFAULT NULL,
  `assignee_id` int(11) DEFAULT NULL,
  `reporter_id` int(11) NOT NULL,
  `page_id` int(11) DEFAULT NULL,
  `due_date` date DEFAULT NULL,
  `estimated_hours` decimal(10,2) DEFAULT NULL,
  `spent_hours` decimal(10,2) DEFAULT 0.00,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `resolved_at` timestamp NULL DEFAULT NULL,
  `common_issue_title` varchar(255) DEFAULT NULL,
  `severity` enum('blocker','critical','major','minor','low') DEFAULT 'major',
  `is_final` tinyint(1) DEFAULT 1,
  PRIMARY KEY (`id`),
  UNIQUE KEY `issue_key` (`issue_key`),
  KEY `idx_project` (`project_id`),
  KEY `idx_status` (`status_id`),
  KEY `idx_assignee` (`assignee_id`),
  KEY `idx_reporter` (`reporter_id`),
  KEY `type_id` (`type_id`),
  KEY `priority_id` (`priority_id`),
  KEY `page_id` (`page_id`),
  KEY `idx_issues_qa_status_id` (`qa_status_id`),
  CONSTRAINT `fk_issues_page_id_project` FOREIGN KEY (`page_id`) REFERENCES `project_pages` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_issues_qa_status_id` FOREIGN KEY (`qa_status_id`) REFERENCES `issue_statuses` (`id`) ON DELETE SET NULL,
  CONSTRAINT `issues_ibfk_1` FOREIGN KEY (`project_id`) REFERENCES `projects` (`id`) ON DELETE CASCADE,
  CONSTRAINT `issues_ibfk_2` FOREIGN KEY (`type_id`) REFERENCES `issue_types` (`id`),
  CONSTRAINT `issues_ibfk_3` FOREIGN KEY (`priority_id`) REFERENCES `issue_priorities` (`id`),
  CONSTRAINT `issues_ibfk_4` FOREIGN KEY (`status_id`) REFERENCES `issue_statuses` (`id`),
  CONSTRAINT `issues_ibfk_5` FOREIGN KEY (`assignee_id`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `issues_ibfk_6` FOREIGN KEY (`reporter_id`) REFERENCES `users` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=296 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

INSERT INTO `issues` VALUES
('27', '6', 'DOM1-1', 'Accordion not programmatically determined', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are accordions that do not have appropriate role, name, and/or state information. Examples include:<br>\r\n- The FAQ accordion on the \"SSSSS\" page lacks ARIA markup.<br>\r\n<br>\r\nAs a result, screen reader users and keyboard-only users may not be able to expand or collapse content.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><img src=\"/PMS/uploads/issues/20260220/issue_699822df0e5546.89687672.png\" alt=\"missing error message\" style=\"max-width:100%; height:auto; cursor:pointer;\" class=\"editable-issue-image\"><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Apply the following changes:<br>\r\n• Code the mentioned elements with native HTML &lt;button&gt; tag.<br>\r\n• Initially set the \'aria-expanded\' attribute to \'false\' for the button. Ensure that the value of the \'aria-expanded\' attribute changes on user interaction via scripting to \'false\' in collapsed state and \'true\' in expanded state.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '1', '1', '1', NULL, NULL, '5', NULL, NULL, NULL, '0.00', '2026-02-20 14:32:03', '2026-02-20 14:33:58', NULL, NULL, 'major', '1'),
('28', '6', 'DOM1-2', 'LT debug', '<p>debug</p>', '1', '1', '1', NULL, NULL, '10', NULL, NULL, NULL, '0.00', '2026-02-20 20:56:38', '2026-02-20 20:56:38', NULL, NULL, 'major', '1'),
('29', '6', 'DOM1-3', 'LT debug updated', '<p>debug update</p>', '1', '1', '1', NULL, NULL, '10', NULL, NULL, NULL, '0.00', '2026-02-20 20:56:55', '2026-02-20 20:57:27', NULL, NULL, 'major', '1'),
('295', '6', 'DOM1-4', 'Accordion not programmatically determined', '<p style=\"margin-bottom:0.2rem;\"><strong>[Actual Result]</strong></p><p>There are accordions that do not have appropriate role, name, and/or state information. Examples include:<br>\r\n- The FAQ accordion on the \"SSSSS\" page lacks ARIA markup.<br>\r\n<br>\r\nAs a result, screen reader users and keyboard-only users may not be able to expand or collapse content.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Incorrect Code]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Screenshot]</strong></p><p><br></p><p style=\"margin-bottom:0.2rem;\"><strong>[Recommendation]</strong></p><p>Apply the following changes:<br>\r\n• Code the mentioned elements with native HTML &lt;button&gt; tag.<br>\r\n• Initially set the \'aria-expanded\' attribute to \'false\' for the button. Ensure that the value of the \'aria-expanded\' attribute changes on user interaction via scripting to \'false\' in collapsed state and \'true\' in expanded state.</p><p style=\"margin-bottom:0.2rem;\"><strong>[Correct Code]</strong></p><p><br></p>', '1', '1', '1', NULL, NULL, '6', '631', NULL, NULL, '0.00', '2026-02-25 21:50:19', '2026-02-25 21:50:19', NULL, NULL, 'major', '1');


-- Table: notifications
DROP TABLE IF EXISTS `notifications`;
CREATE TABLE `notifications` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
